import React, {
  useEffect,
  useState
} from "react";

import {
  useNavigate,
  useParams
} from "react-router-dom";

import "./AppraisalForm.css";

export default function AppraisalForm() {

  const navigate =
    useNavigate();

  const { id } =
    useParams();

  /* ROLE BASE */
  const loggedUser =
    JSON.parse(
      localStorage.getItem(
        "loggedInUser"
      )
    ) || {};

  const base =
    loggedUser?.role?.toUpperCase()
      === "ADMIN"
      ? "/admin-dashboard"
      : "/employee-dashboard";

  /* STATE */
  const [employees,
    setEmployees] =
    useState([]);

  const [formData,
    setFormData] =
    useState({

      employeeName: "",
      department: "",
      period: "Jan 2024 - Dec 2024",
      rating: "",
      status: "Pending"

    });

  const [errors,
    setErrors] =
    useState({});

  /* LOAD EMPLOYEES */
  useEffect(() => {

    const emp =
      JSON.parse(
        localStorage.getItem(
          "employees"
        )
      ) || [];

    setEmployees(emp);

  }, []);

  /* LOAD EDIT DATA FROM BACKEND */
  useEffect(() => {

    if (!id) return;

    const load =
      async () => {

        try {

          const token =
            localStorage.getItem(
              "token"
            );

          const res =
            await fetch(
              `http://localhost:8080/api/appraisals/${id}`,
              {
                headers: {
                  Authorization:
                    `Bearer ${token}`
                }
              }
            );

          const data =
            await res.json();

          setFormData({

            employeeName:
              data.employeeName,

            department:
              data.department,

            period:
              data.reviewPeriod,

            rating:
              data.rating,

            status:
              data.status

          });

        }
        catch (err) {

          console.error(err);

        }

      };

    load();

  }, [id]);

  /* HANDLE CHANGE */
  const handleChange =
    (e) => {

      const {
        name,
        value
      } = e.target;

      if (name === "employeeName") {

        const emp =
          employees.find(
            e =>
              `${e.firstName} ${e.lastName}`
                === value
          );

        setFormData({

          ...formData,

          employeeName:
            value,

          department:
            emp
              ? emp.department
              : ""

        });

        return;

      }

      setFormData({

        ...formData,

        [name]:
          value

      });

    };

  /* VALIDATION */
  const validate =
    () => {

      let temp =
        {};

      if (!formData.employeeName)
        temp.employeeName =
          "Employee required";

      if (!formData.rating)
        temp.rating =
          "Rating required";

      setErrors(temp);

      return Object
        .keys(temp)
        .length === 0;

    };

  /* SUBMIT */
  const handleSubmit =
    async (e) => {

      e.preventDefault();

      if (!validate())
        return;

      try {

        const token =
          localStorage.getItem(
            "token"
          );

        const method =
          id
            ? "PUT"
            : "POST";

        const url =
          id
            ? `http://localhost:8080/api/appraisals/${id}`
            : `http://localhost:8080/api/appraisals`;

        await fetch(
          url,
          {
            method,

            headers: {

              "Content-Type":
                "application/json",

              Authorization:
                `Bearer ${token}`

            },

            body:
              JSON.stringify({

                employeeName:
                  formData.employeeName,

                department:
                  formData.department,

                reviewPeriod:
                  formData.period,

                rating:
                  parseFloat(
                    formData.rating
                  ),

                status:
                  formData.status,

                remarks:
                  "",

                salaryIncrease:
                  0

              })

          }
        );

        alert(
          id
            ? "Updated Successfully"
            : "Created Successfully"
        );

        navigate(
          `${base}/appraisal`
        );

      }
      catch (err) {

        console.error(err);

      }

    };

  /* UI */
  return (

    <div className="appraisal-form-scope">

      <div className="appraisal-form-card">

        <h2>
          {id
            ? "Edit Employee Appraisal"
            : "Add Employee Appraisal"}
        </h2>

        <form
          className="appraisal-form"
          onSubmit={
            handleSubmit
          }
        >

          <label>
            Employee Name
          </label>

          <select
            name="employeeName"
            value={
              formData.employeeName
            }
            onChange={
              handleChange
            }
          >

            <option value="">
              Select Employee
            </option>

            {employees.map(
              emp => (

                <option
                  key={
                    emp.id
                  }
                  value={
                    `${emp.firstName} ${emp.lastName}`
                  }
                >

                  {emp.firstName}
                  {" "}
                  {emp.lastName}

                </option>

              )
            )}

          </select>

          <label>
            Department
          </label>

          <input
            name="department"
            value={
              formData.department
            }
            disabled
          />

          <label>
            Review Period
          </label>

          <input
            name="period"
            value={
              formData.period
            }
            onChange={
              handleChange
            }
          />

          <label>
            Rating
          </label>

          <input
            type="number"
            name="rating"
            value={
              formData.rating
            }
            onChange={
              handleChange
            }
          />

          <label>
            Status
          </label>

          <select
            name="status"
            value={
              formData.status
            }
            onChange={
              handleChange
            }
          >

            <option>
              Pending
            </option>

            <option>
              Approved
            </option>

            <option>
              Rejected
            </option>

          </select>

          <div className="appraisal-btn-row">

            <button
              type="submit"
              className="appraisal-save-btn"
            >
              Save
            </button>

            <button
              type="button"
              className="appraisal-cancel-btn"
              onClick={() =>
                navigate(
                  `${base}/appraisal`
                )
              }
            >
              Cancel
            </button>

          </div>

        </form>

      </div>

    </div>

  );

}
